mapper.update:
UPDATE approval_signs
SET status = #{status, typeHandler=org.apache.ibatis.type.EnumTypeHandler},
    comment = #{comment},
    updated_at = #{updatedAt}
WHERE id = #{id}

mapper.select:
SELECT id, approval_id, approver_id, target_id, stage, status, comment, created_at, updated_at
FROM approval_signs
WHERE id = #{id}

SELECT id, approval_id, approver_id, target_id, stage, status, comment, created_at, updated_at
FROM approval_signs
WHERE approval_id = #{approvalId} AND id = #{signId}

SELECT id, approval_id, approver_id, target_id, stage, status, comment, created_at, updated_at
FROM approval_signs
WHERE approval_id = #{approvalId} 
  AND target_id = #{targetId} 
  AND stage = #{stage, typeHandler=org.apache.ibatis.type.EnumTypeHandler}
